usage.declarative_schema:
#[Model(model: OrderModel::class)]
class OrderSchema {
    #[PrimaryKey]
    public int $id;

    #[Field(searchable: true)]
    public string $reference;

    #[Field(cast: Cast::float)]
    public float $total;

    #[BelongsTo(relation: UserSchema::class, foreignKey: 'user_id')]
    public ?UserSchema $user;
}
